/// <summary>
/// The <c>ETGTermoNumberReportContract</c> class is the data contract class for termo number report
/// report.
/// </summary>
    [
        DataContractAttribute,
        SysOperationGroupAttribute('DateRange', "@SYS41297", '1'),
        SysOperationGroupAttribute('Invoice', "Invoice", '2')
    ]
    class ETGTermoNumberReportContract implements SysOperationValidatable
    {
        FromDate                fromDate;
        ToDate                  toDate;
        CustInvoiceId           invoiceId;
        CustAccount             custAccount;
        ModuleSalesPurch        moduleSalesPurch;

}

Method.Source:
[
DataMemberAttribute('FromDate'),
SysOperationLabelAttribute(literalStr("@SYS5209")),
SysOperationHelpTextAttribute(literalStr("@SYS5209")),
SysOperationDisplayOrderAttribute('1'),
SysOperationGroupMemberAttribute('DateRange')
]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[
DataMemberAttribute('ToDate'),
SysOperationLabelAttribute(literalStr("@SYS14656")),
SysOperationHelpTextAttribute(literalStr("@SYS14656")),
SysOperationDisplayOrderAttribute('2'),
SysOperationGroupMemberAttribute('DateRange')
]
public ToDate parmToDate(ToDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

[
    DataMemberAttribute('InvoiceId'),
    SysOperationLabelAttribute(literalStr("@SYS4726")),
    SysOperationHelpTextAttribute(literalStr("@SYS4726")),
    SysOperationDisplayOrderAttribute('3'),
    SysOperationGroupMemberAttribute('Invoice')
]
public CustInvoiceId parmInvoiceId(CustInvoiceId _invoiceId = invoiceId)
{
    invoiceId = _invoiceId;
    return invoiceId;
}

[
    DataMemberAttribute('CustAccount'),
    SysOperationLabelAttribute(literalStr("@SYS7149")),
    SysOperationHelpTextAttribute(literalStr("@SYS7149")),
    SysOperationDisplayOrderAttribute('4'),
    SysOperationGroupMemberAttribute('Invoice')
]
public CustAccount parmCustAccount(CustAccount _custAccount = custAccount)
{
    custAccount = _custAccount;
    return custAccount;
}

[DataMemberAttribute('ModuleSalesPurch')]
public ModuleSalesPurch parmModuleSalesPurch(ModuleSalesPurch _moduleSalesPurch = moduleSalesPurch)
{
    moduleSalesPurch = _moduleSalesPurch;
    return moduleSalesPurch;
}

public boolean validate()
{
    boolean isValid = true;
    if (!fromDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180311"));
    }
    if (!toDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180217"));
    }
    if (fromDate > toDate)
    {
        isValid = checkFailed("@SYS300457");
    }

    return isValid;
}
